import React, { useState, Suspense } from 'react'
import { TreeViewRelationship } from '@fs/zion-icon'
import { ListItem, useOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { setUsersRelationshipViewingStatus } from '@fs/zion-relationship-service'
import OptInOverlaySkeleton from '../OptInOverlaySkeleton'
import { relationshipStatusOptions } from '../useRelationshipReducer'

const OptInOverlay = React.lazy(() => import('../OptInOverlay'))

async function attemptSetUserStatusToOptIn({ dispatchStatusCallback }) {
  const optInSuccess = await setUsersRelationshipViewingStatus(true)

  dispatchStatusCallback(optInSuccess ? relationshipStatusOptions.userOptIn : relationshipStatusOptions.userOptOut)
}

async function attemptSetUserStatusToOptOut({ dispatchStatusCallback }) {
  const optOutSuccess = await setUsersRelationshipViewingStatus(false)

  dispatchStatusCallback(optOutSuccess ? relationshipStatusOptions.userOptOut : relationshipStatusOptions.userOptIn)
}

export default function UserOptedOutView({ setShowStatusParams, dispatchRelationshipViewingStatus, track }) {
  const overlay = useOverlay()
  const { t } = useTranslation()
  const [disableActions, setDisableActions] = useState()

  function attemptUserOptIn(event) {
    setDisableActions(true)
    track('enableRelationshipViewing:clicked', event?.target)

    attemptSetUserStatusToOptIn({ dispatchStatusCallback: callBack })

    function callBack(newStatusString) {
      dispatchRelationshipViewingStatus(newStatusString)

      if (newStatusString === relationshipStatusOptions.userOptIn)
        setShowStatusParams({
          message: t('relation-view.opted-in', 'Relationship Viewing enabled'),
          actionLabel: t('undo', 'UNDO'),
          actionCallback: attemptUserOptOut,
          type: 'success',
        })

      if (newStatusString === relationshipStatusOptions.userOptOut) {
        setShowStatusParams({
          message: t('relation-view.opt-in.error', 'Opt in failed'),
          actionLabel: t('relation-view.retry!', 'TRY AGAIN'),
          actionCallback: attemptUserOptIn,
          type: 'error',
        })

        setDisableActions(false)
      }
    }
  }

  function attemptUserOptOut(event) {
    setDisableActions(true)
    track('enableRelationshipViewingDialog:undo:clicked', event?.target)

    attemptSetUserStatusToOptOut({ dispatchStatusCallback: callBack })

    function callBack(newStatusString) {
      dispatchRelationshipViewingStatus(newStatusString)
      if (newStatusString === relationshipStatusOptions.userOptOut)
        setShowStatusParams({
          message: t('relation-view.opted-out', 'You have opted out of relationship viewing'),
          type: 'success',
        })

      if (newStatusString === relationshipStatusOptions.userOptIn) {
        setShowStatusParams({
          message: t('relation-view.opt-out.error', 'Opt out failed'),
          actionLabel: t('relation-view.retry!', 'TRY AGAIN'),
          actionCallback: attemptUserOptOut,
          type: 'error',
        })

        setDisableActions(false)
      }
    }
  }

  return (
    <>
      <ListItem
        primaryText={t('relation-view.opt-in', 'Enable Relationship Viewing')}
        onClick={overlay.handleClick}
        disabled={disableActions}
        startElement={<ListItem.Icon Icon={TreeViewRelationship} />}
      />
      {overlay.isOpen && (
        <Suspense fallback={<OptInOverlaySkeleton overlay={overlay} />}>
          <OptInOverlay overlay={overlay} onEnable={attemptUserOptIn} />
        </Suspense>
      )}
    </>
  )
}
